 638 |                 function findSentenceRange(rootDoc, startNode, startOffset, pageBoundary) {
 639 |                     const sentenceEndRegex = /[.!?]/;
 640 |                     
 641 |                     // Helper: TreeWalker for linear text traversal within the page
 642 |                     function createWalker(root) {
 643 |                         return rootDoc.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
 644 |                     }
 645 | 
 646 |                     // 1. BACKWARD SCAN (Find start)
 647 |                     let currentStartNode = startNode;
 648 |                     let currentStartOffset = startOffset;
 649 |                     let finalStartNode = startNode;
 650 |                     let finalStartOffset = 0;
 651 | 
 652 |                     let textBefore = currentStartNode.textContent.substring(0, currentStartOffset);
 653 |                     let lastPuncIndex = -1;
 654 |                     for(let i = textBefore.length - 1; i >= 0; i--) {
 655 |                         if(sentenceEndRegex.test(textBefore[i])) { lastPuncIndex = i; break; }
 656 |                     }
 657 | 
 658 |                     if (lastPuncIndex !== -1) {
 659 |                         finalStartOffset = lastPuncIndex + 1;
 660 |                         if(currentStartNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
 661 |                     } else {
 662 |                         const walker = createWalker(pageBoundary);
 663 |                         walker.currentNode = currentStartNode;
 664 |                         let prevNode = walker.previousNode();
 665 |                         let foundStart = false;
 666 | 
 667 |                         while (prevNode && !foundStart) {
 668 |                             const text = prevNode.textContent;
 669 |                             for (let i = text.length - 1; i >= 0; i--) {
 670 |                                 if (sentenceEndRegex.test(text[i])) {
 671 |                                     finalStartNode = prevNode; finalStartOffset = i + 1;
 672 |                                     if(text[finalStartOffset] === ' ') finalStartOffset++;
 673 |                                     foundStart = true; break;
 674 |                                 }
 675 |                             }
 676 |                             if (!foundStart) {
 677 |                                 finalStartNode = prevNode; finalStartOffset = 0;
 678 |                                 prevNode = walker.previousNode();
 679 |                             }
 680 |                         }
 681 |                     }
 682 | 
 683 |                     // 2. FORWARD SCAN (Find end)
 684 |                     let currentEndNode = startNode;
 685 |                     let currentEndOffset = startOffset;
 686 |                     let finalEndNode = startNode;
 687 |                     let finalEndOffset = startNode.textContent.length;
 688 | 
 689 |                     let textAfter = currentEndNode.textContent.substring(currentEndOffset);
 690 |                     let nextPuncIndex = textAfter.search(sentenceEndRegex);
 691 | 
 692 |                     if (nextPuncIndex !== -1) {
 693 |                         finalEndOffset = currentEndOffset + nextPuncIndex + 1;
 694 |                     } else {
 695 |                         const walker = createWalker(pageBoundary);
 696 |                         walker.currentNode = currentEndNode;
 697 |                         let nextNode = walker.nextNode();
 698 |                         let foundEnd = false;
 699 | 
 700 |                         while (nextNode && !foundEnd) {
 701 |                             const text = nextNode.textContent;
 702 |                             const puncIdx = text.search(sentenceEndRegex);
 703 |                             if (puncIdx !== -1) {
 704 |                                 finalEndNode = nextNode; finalEndOffset = puncIdx + 1;
 705 |                                 foundEnd = true;
 706 |                             } else {
 707 |                                 finalEndNode = nextNode; finalEndOffset = text.length;
 708 |                                 nextNode = walker.nextNode();
 709 |                             }
 710 |                         }
 711 |                     }
 712 | 
 713 |                     // Create the final Range
 714 |                     const r = rootDoc.createRange();
 715 |                     try {
 716 |                         r.setStart(finalStartNode, finalStartOffset);
 717 |                         r.setEnd(finalEndNode, finalEndOffset);
 718 |                         return r;
 719 |                     } catch (e) {
 720 |                         console.warn("Sentence Range Error:", e);
 721 |                         return null;
 722 |                     }
 723 |                 }
 724 |             } catch (err) {
 725 |                 console.error("Iframe Load Error:", err);
 726 |             }
 727 |         }, 100);
 728 |     };
