 759 |     const applyConstraints = () => {
 760 |         const vw = window.innerWidth;
 761 |         const vh = window.innerHeight;
 762 |         const { width, height } = contentDims.current;
 763 |         const s = state.current;
 764 |         const v = velocity.current;
 765 |         
 766 |         const visualW = width * s.scale;
 767 |         const visualH = height * s.scale;
 768 | 
 769 |         // X Constraint
 770 |         if (visualW < vw) {
 771 |             s.x = (vw - visualW) / 2;
 772 |             v.x = 0;
 773 |         } else {
 774 |             if (s.x > 0) { s.x = 0; v.x = 0; }
 775 |             if (s.x < vw - visualW) { s.x = vw - visualW; v.x = 0; }
 776 |         }
 777 | 
 778 |         // Y Constraint
 779 |         if (visualH < vh) {
 780 |             s.y = (vh - visualH) / 2;
 781 |             v.y = 0;
 782 |         } else {
 783 |             if (s.y > 0) { s.y = 0; v.y = 0; }
 784 |             if (s.y < vh - visualH) { s.y = vh - visualH; v.y = 0; }
 785 |         }
