 796 |             if (Math.abs(v.y) < 0.5) v.y = 0;
 797 | 
 798 |             if (v.x !== 0 || v.y !== 0) {
 799 |                 v.x *= CONFIG.friction;
 800 |                 v.y *= CONFIG.friction;
 801 |                 state.current.x += v.x;
 802 |                 state.current.y += v.y;
 803 |             }
 804 |         }
