 254 |         val hasHeadset = am.isWiredHeadsetOn || am.isBluetoothA2dpOn
 255 | 
 256 |         if (prefs.getBoolean("headset_only", true) && !hasHeadset) return
 257 |         if (!isReady) return
 258 | 
 259 |         // Priority 0 (Low): Discard if TTS is already speaking to prevent overlap
 260 |         if (priority == 0 && tts.isSpeaking) {
