 274 |         // Priority 2 (Critical): Flush queue. Priority 1 (Normal): Add to queue.
 275 |         val queueMode = if (priority >= 2) TextToSpeech.QUEUE_FLUSH else TextToSpeech.QUEUE_ADD
 276 |         
 277 |         if (priority >= 2) tts.stop() // Hard interrupt for critical messages
 278 |         
 279 |         tts.speak(message, queueMode, null, id)
