 320 |     private fun processJson(rawJson: String) {
 321 |         // Last line of defense: check if system is active before processing new data
 322 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
 323 |         if (!prefs.getBoolean("is_active", true)) return
 324 | 
 325 |         if (!isReady) {
 326 |             Handler(Looper.getMainLooper()).postDelayed({ processJson(rawJson) }, 1000)
 327 |             return
 328 |         }
 329 |         try {
 330 |             // 1. Extract JSON block (handles AI conversational noise or markdown blocks)
 331 |             val firstBrace = rawJson.indexOf("{")
 332 |             val lastBrace = rawJson.lastIndexOf("}")
 333 |             
 334 |             if (firstBrace == -1 || lastBrace == -1 || lastBrace < firstBrace) {
 335 |                 DebugLogger.log("JSON_ERR", "No valid JSON structure found in response")
 336 |                 speakStatus("Error: Server returned unreadable data.", 2)
 337 |                 return
 338 |             }
 339 |             
 340 |             val jsonStr = rawJson.substring(firstBrace, lastBrace + 1)
 341 |             if (firstBrace > 0 || lastBrace < rawJson.length - 1) {
 342 |                 DebugLogger.log("JSON_RECOVERY", "Extracted JSON block from noisy response")
 343 |             }
 344 | 
 345 |             val root = JSONObject(jsonStr)
 346 |             val solutions = root.optJSONArray("solutions") ?: return
 347 |             if (solutions.length() == 0) return
 348 |             
 349 |             isProcessingBatch = true
 350 |             synthesisQueue.clear()
 351 |             val batchId = System.currentTimeMillis()
 352 | 
 353 |             for (i in 0 until solutions.length()) {
 354 |                 val item = solutions.optJSONObject(i) ?: continue
 355 |                 val type = item.optString("type", "sa")
 356 |                 val rawNum = item.optString("number", (i + 1).toString())
 357 |                 val number = rawNum.padStart(3, '0')
 358 |                 
 359 |                 val stepsArray = item.optJSONArray("steps")
 360 |                 val stepsBuilder = StringBuilder()
 361 |                 if (stepsArray != null) {
 362 |                     for (j in 0 until stepsArray.length()) { stepsBuilder.append(stepsArray.optString(j)).append(". ") }
 363 |                 }
 364 |                 
 365 |                 val typeName = when(type) { 
 366 |                     "wo" -> "Worked out solution"; "tf" -> "True or False"; "mc" -> "Multiple Choice"; 
 367 |                     "ma" -> "Matching"; "fill" -> "Fill in the blank"; else -> "Question" 
 368 |                 }
 369 |                 
 370 |                 var speech = if (type == "wo") "$typeName $rawNum. ${stepsBuilder} Final answer: ${item.optString("answer")}" 
 371 |                              else "$typeName $rawNum. Answer: ${item.optString("answer")}"
 372 | 
 373 |                 // Heavy Sanitization for TTS stability
 374 |                 speech = speech.replace(Regex("[^a-zA-Z0-9.,!?;: ]"), " ").replace("\\s+".toRegex(), " ").trim()
 375 | 
 376 |                 val file = File(audioFolder, "${type}_${batchId}_${number}.wav")
 377 |                 synthesisQueue.add(speech to file)
 378 |             }
 379 | 
 380 |             pendingSyntheses.set(synthesisQueue.size)
 381 |             speakStatus("Processing ${synthesisQueue.size} solutions", 1)
 382 |             processNextInQueue()
 383 |         } catch (e: Exception) {
