 532 |     private fun playCurrent() {
 533 |         val list = playlists[currentType] ?: return
 534 |         if (currentIndex < 0 || currentIndex >= list.size) currentIndex = 0
 535 |         val file = list[currentIndex]
 536 | 
 537 |         // --- STEALTH CHECK ---
 538 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
 539 |         val am = getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
 540 |         if (prefs.getBoolean("headset_only", true) && !am.isWiredHeadsetOn && !am.isBluetoothA2dpOn) {
 541 |             DebugLogger.log("STEALTH", "Playback blocked: Stealth mode active and no headset found.")
 542 |             return
 543 |         }
 544 | 
 545 |         DebugLogger.log("MEDIA_TRACE", "Attempting playback of ${file.name} (Size: ${file.length()} bytes)")
 546 | 
 547 |         // ANTI-LOOP GUARD: If file is missing or empty, do not play.
 548 |         // Increased to 1KB to ensure a valid audio header exists.
 549 |         if (!file.exists() || file.length() < 1024) {
 550 |             DebugLogger.log("MEDIA_ERR", "ABORT: File ${file.name} size is ${file.length()} bytes. (Min 1024 required)")
 551 |             speakStatus("Audio file is still being generated. Please try again in a moment.", 2)
 552 |             return
 553 |         }
 554 | 
 555 |         try {
 556 |             if (mediaPlayer == null) {
 557 |                 mediaPlayer = MediaPlayer().apply {
 558 |                     setDataSource(file.absolutePath)
 559 |                     setAudioAttributes(android.media.AudioAttributes.Builder()
 560 |                         .setUsage(android.media.AudioAttributes.USAGE_MEDIA)
 561 |                         .setContentType(android.media.AudioAttributes.CONTENT_TYPE_MUSIC)
 562 |                         .build())
 563 |                     prepareAsync()
 564 |                     setOnPreparedListener { 
 565 |                         DebugLogger.log("MEDIA", "Starting Playback: ${file.name}")
 566 |                         start() 
 567 |                     }
 568 |                     setOnErrorListener { _, what, extra ->
 569 |                         DebugLogger.log("MEDIA_ERR", "MediaPlayer Error: $what / $extra")
 570 |                         stopAllPlayback()
 571 |                         true
 572 |                     }
 573 |                     setOnCompletionListener {
 574 |                         DebugLogger.log("MEDIA", "Playback finished for ${file.name}")
 575 |                         // Mandatory delay to prevent rapid-fire loops
 576 |                         handler.postDelayed({ playNext() }, 1000)
 577 |                     }
 578 |                 }
 579 |             }
 580 |         } catch (e: Exception) { 
 581 |             DebugLogger.log("MEDIA_CRITICAL", "Failed to init MediaPlayer: ${e.message}")
 582 |             stopAllPlayback()
 583 |         }
 584 |     }
