 586 |     private fun pauseAudio() {
 587 |         val list = playlists[currentType]
 588 |         if (list.isNullOrEmpty()) {
 589 |             speakStatus("No solutions loaded to play.", 2)
 590 |             return
 591 |         }
 592 |         
 593 |         if (mediaPlayer?.isPlaying == true) {
 594 |             mediaPlayer?.pause()
 595 |             speakStatus("Paused", 2)
 596 |             updateMediaSessionState(false)
 597 |         } else {
 598 |             speakStatus("Resumed", 2)
 599 |             if (mediaPlayer == null) {
 600 |                 // Reconstruction: The player was released or never started
 601 |                 playCurrent()
 602 |             } else {
 603 |                 mediaPlayer?.start()
 604 |                 updateMediaSessionState(true)
 605 |             }
 606 |         }
 607 |     }
