 609 |     private fun updateMediaSessionState(isPlaying: Boolean) {
 610 |         try {
 611 |             val session = mediaSession
 612 |             if (session == null || !session.isActive) return
 613 |             
 614 |             val state = if (isPlaying) PlaybackStateCompat.STATE_PLAYING else PlaybackStateCompat.STATE_PAUSED
 615 |             session.setPlaybackState(PlaybackStateCompat.Builder()
 616 |                 .setActions(PlaybackStateCompat.ACTION_PLAY_PAUSE or PlaybackStateCompat.ACTION_PLAY or PlaybackStateCompat.ACTION_STOP)
 617 |                 .setState(state, PlaybackStateCompat.PLAYBACK_POSITION_UNKNOWN, 1.0f)
 618 |                 .build())
 619 |         } catch (e: Exception) {
 620 |             DebugLogger.log("SESSION_ERR", "State update failed: ${e.message}")
 621 |         }
 622 |     }
