 747 |     private var isClaiming = false
 748 |     private fun claimMediaFocus() {
 749 |         val now = System.currentTimeMillis()
 750 |         // Cooldown: Stop the OS focus-war loop (5-second minimum gap)
 751 |         if (isFocusHeld || isClaiming || (now - lastFocusLossTime < 5000)) return
 752 |         isClaiming = true
 753 | 
 754 |         val am = getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
 755 |         
 756 |         if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
 757 |             val focusRequest = android.media.AudioFocusRequest.Builder(android.media.AudioManager.AUDIOFOCUS_GAIN)
 758 |                 .setAudioAttributes(android.media.AudioAttributes.Builder()
 759 |                     .setUsage(android.media.AudioAttributes.USAGE_MEDIA)
 760 |                     .setContentType(android.media.AudioAttributes.CONTENT_TYPE_MUSIC)
 761 |                     .build())
 762 |                 .setOnAudioFocusChangeListener { focusChange ->
 763 |                     when (focusChange) {
 764 |                         android.media.AudioManager.AUDIOFOCUS_LOSS,
 765 |                         android.media.AudioManager.AUDIOFOCUS_LOSS_TRANSIENT -> {
 766 |                             isFocusHeld = false
 767 |                             lastFocusLossTime = System.currentTimeMillis()
 768 |                             DebugLogger.log("SESSION", "Focus Surrendered")
 769 |                             handler.postDelayed({ isClaiming = false }, 5000)
 770 |                         }
 771 |                         android.media.AudioManager.AUDIOFOCUS_GAIN -> {
 772 |                             isFocusHeld = true
 773 |                             DebugLogger.log("SESSION", "Focus Re-Gained")
 774 |                         }
 775 |                     }
 776 |                 }
 777 |                 .build()
 778 |             
 779 |             val result = am.requestAudioFocus(focusRequest)
 780 |             if (result == android.media.AudioManager.AUDIOFOCUS_REQUEST_GRANTED) {
 781 |                 isFocusHeld = true
 782 |                 isClaiming = false
 783 |                 DebugLogger.log("SESSION", "Focus Secured")
 784 |                 mediaSession?.isActive = true
 785 |                 startSilentLoop()
 786 |             } else {
 787 |                 isClaiming = false
 788 |                 lastFocusLossTime = System.currentTimeMillis()
 789 |             }
 790 |         } else {
 791 |             isClaiming = false
 792 |         }
 793 |     }
