 839 |     private fun handleHeadsetCommand() {
 840 |         val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
 841 |         val isScreenOff = !pm.isInteractive
 842 |         
 843 |         DebugLogger.log("HEADSET_EVENT", "--- HEADSET CLICK DETECTED ---")
 844 |         
 845 |         // Stealth micro-tick (40ms at low power)
 846 |         vibrator?.vibrate(VibrationEffect.createOneShot(40, 60))
 847 |         DebugLogger.log("HEADSET_EVENT", "Vibration Triggered Successfully")
 848 | 
 849 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
 850 |         val actuallyActive = prefs.getBoolean("is_active", true)
 851 |         
 852 |         if (!actuallyActive) {
 853 |             DebugLogger.log("HEADSET_EVENT", "Ignored: System is marked INACTIVE in SharedPreferences")
 854 |             return
 855 |         }
 856 | 
 857 |         if (isScreenOff) {
 858 |             DebugLogger.log("HEADSET_EVENT", "SCREEN IS OFF -> Branching to wakeDevice()")
 859 |             wakeDevice(pm)
 860 |         } else {
 861 |             DebugLogger.log("HEADSET_EVENT", "SCREEN IS ON -> Broadcasting SHUTTER signal")
 862 |             val intent = Intent("com.universal.app.HEADSET_TRIGGER_SHUTTER")
 863 |             sendBroadcast(intent)
 864 |         }
 865 |     }
