 867 |     private var wakeRetryCount = 0
 868 |     private fun wakeDevice(pm: PowerManager) {
 869 |         DebugLogger.log("WAKE_TRACE", "Step 1: Entering wakeDevice() function")
 870 |         
 871 |         if (pm.isInteractive) {
 872 |             DebugLogger.log("WAKE_TRACE", "Step 1.1: Cancelled - Device is already interactive")
 873 |             return
 874 |         }
 875 | 
 876 |         try {
 877 |             // 1. Prepare Intent
 878 |             DebugLogger.log("WAKE_TRACE", "Step 2: Building WakeActivity Intent")
 879 |             val intent = Intent(this, WakeActivity::class.java).apply {
 880 |                 addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or 
 881 |                          Intent.FLAG_ACTIVITY_CLEAR_TOP or 
 882 |                          Intent.FLAG_ACTIVITY_SINGLE_TOP)
 883 |             }
 884 |             
 885 |             val pendingIntent = PendingIntent.getActivity(
 886 |                 this, 
 887 |                 999, 
 888 |                 intent, 
 889 |                 PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
 890 |             )
 891 |             DebugLogger.log("WAKE_TRACE", "Step 3: PendingIntent created (ID: 999)")
 892 | 
 893 |             // 2. Build High-Priority Notification
 894 |             val builder = NotificationCompat.Builder(this, "PlaybackChannel")
 895 |                 .setSmallIcon(android.R.drawable.ic_lock_power_off)
 896 |                 .setContentTitle("System Wake Request")
 897 |                 .setContentText("Click to restore visual interface")
 898 |                 .setPriority(NotificationCompat.PRIORITY_MAX)
 899 |                 .setCategory(NotificationCompat.CATEGORY_ALARM)
 900 |                 .setFullScreenIntent(pendingIntent, true)
 901 |                 .setVisibility(NotificationCompat.VISIBILITY_PUBLIC)
 902 |                 .setVibrate(longArrayOf(0L)) // Mute system vibration (0ms)
 903 |                 .setAutoCancel(true)
 904 |             DebugLogger.log("WAKE_TRACE", "Step 4: Notification Builder configured with FullScreenIntent")
 905 | 
 906 |             val nm = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
 907 |             
 908 |             // 3. Physical Hardware Wake - Using FULL_WAKE_LOCK for maximum power
 909 |             @Suppress("DEPRECATION")
 910 |             val wl = pm.newWakeLock(PowerManager.FULL_WAKE_LOCK or PowerManager.ACQUIRE_CAUSES_WAKEUP or PowerManager.ON_AFTER_RELEASE, "UniversalApp::EmergencyWake")
 911 |             
 912 |             DebugLogger.log("WAKE_TRACE", "Step 5: WakeLock created. Attempting acquire(10s)...")
 913 |             wl.acquire(10000L)
 914 |             DebugLogger.log("WAKE_TRACE", "Step 6: WakeLock ACQUIRED")
 915 | 
 916 |             // 4. Fire Notification
 917 |             DebugLogger.log("WAKE_TRACE", "Step 7: Dispatching Notification to NotificationManager")
 918 |             nm.notify(99, builder.build())
 919 |             
 920 |             // 5. Fire Activity Directly
 921 |             DebugLogger.log("WAKE_TRACE", "Step 8: Calling startActivity(WakeActivity)")
 922 |             startActivity(intent)
 923 |             DebugLogger.log("WAKE_TRACE", "Step 9: startActivity command sent")
 924 | 
 925 |             verifyPhysicalWake(pm, 0)
 926 |             
 927 |             handler.postDelayed({
 928 |                 DebugLogger.log("WAKE_TRACE", "Step 10: Cleaning up Wake Notification")
 929 |                 nm.cancel(99)
 930 |             }, 5000)
 931 | 
 932 |         } catch (e: Exception) {
 933 |             DebugLogger.log("WAKE_CRITICAL", "CRASH in wake sequence: ${e.message}")
 934 |             e.printStackTrace()
 935 |         }
 936 |     }
