 938 |     private fun verifyPhysicalWake(pm: PowerManager, checkCount: Int) {
 939 |         handler.postDelayed({
 940 |             val logicallyOn = pm.isInteractive
 941 |             DebugLogger.log("WAKE_VERIFY", "Check #$checkCount: Interactive=$logicallyOn")
 942 | 
 943 |             if (logicallyOn) {
 944 |                 wakeRetryCount = 0
 945 |                 // Service stays silent; we wait for WakeActivity.onWindowFocusChanged
 946 |                 DebugLogger.log("WAKE_VERIFY", "Logical wake confirmed. Waiting for Activity Focus signal.")
 947 |             } else if (checkCount < 8) { // Increased checks for slower devices
 948 |                 verifyPhysicalWake(pm, checkCount + 1)
 949 |             } else {
 950 |                 if (wakeRetryCount < 2) {
 951 |                     wakeRetryCount++
 952 |                     DebugLogger.log("WAKE_RECOVER", "Retrying wake sequence...")
 953 |                     speakStatus("Retry wake", true)
 954 |                     wakeDevice(pm)
 955 |                 } else {
 956 |                     speakStatus("Wake failed. Check battery optimization.", true)
 957 |                     wakeRetryCount = 0
 958 |                 }
 959 |             }
 960 |         }, 500)
 961 |     }
