 967 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
 968 |         val am = getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
 969 |         if (prefs.getBoolean("headset_only", true) && !am.isWiredHeadsetOn && !am.isBluetoothA2dpOn) {
 970 |             DebugLogger.log("STEALTH", "Specific playback blocked: Stealth mode active.")
