 972 |         }
 973 | 
 974 |         // --- DIAGNOSTIC PRE-FLIGHT ---
 975 |         if (!file.exists()) {
 976 |             DebugLogger.log("DIAGNOSTIC", "FAILURE: File $fileName does not exist on disk.")
 977 |             speakStatus("Solution file not found. It may still be generating.", true)
 978 |             return
 979 |         }
 980 | 
 981 |         if (file.length() == 0L) {
