 989 |             speakStatus("Audio file is corrupted.", true)
 990 |             return
 991 |         }
 992 | 
 993 |         synchronized(this) {
 994 |             stopAllPlayback()
 995 |             DebugLogger.log("MEDIA", "Attempting playback: ${file.name}")
 996 |             
 997 |             try {
 998 |                 val newPlayer = MediaPlayer()
 999 |                 newPlayer.setDataSource(file.absolutePath)
1000 |                 newPlayer.setAudioAttributes(android.media.AudioAttributes.Builder()
1001 |                     .setUsage(android.media.AudioAttributes.USAGE_MEDIA)
1002 |                     .setContentType(android.media.AudioAttributes.CONTENT_TYPE_MUSIC)
1003 |                     .build())
1004 |                 
1005 |                 newPlayer.setOnPreparedListener { 
1006 |                     it.start()
1007 |                     updateMediaSessionState(true)
1008 |                 }
1009 |                 
1010 |                 newPlayer.setOnErrorListener { _, what, extra ->
1011 |                     val hwReason = when(extra) {
1012 |                         MediaPlayer.MEDIA_ERROR_MALFORMED -> "Malformed bitstream"
1013 |                         MediaPlayer.MEDIA_ERROR_IO -> "File IO Error"
1014 |                         MediaPlayer.MEDIA_ERROR_UNSUPPORTED -> "Unsupported codec"
1015 |                         else -> "Low-level hardware error"
1016 |                     }
1017 |                     DebugLogger.log("DIAGNOSTIC", "HARDWARE FAILURE: Code $what / Reason: $hwReason")
1018 |                     speakStatus("Hardware playback error: $hwReason", true)
1019 |                     stopAllPlayback()
1020 |                     true
1021 |                 }
1022 | 
1023 |                 mediaPlayer = newPlayer
1024 |                 mediaPlayer?.prepareAsync()
1025 |             } catch (e: Exception) {
1026 |                 DebugLogger.log("DIAGNOSTIC", "CRITICAL: Exception during MediaPlayer init: ${e.message}")
1027 |                 stopAllPlayback()
1028 |             }
1029 |         }
1030 |     }
